package com.maum.backend.service

import com.maum.backend.entity.follow.FollowEntity
import com.maum.backend.entity.user.UserEntity
import com.maum.backend.exception.AlreadyFollowingException
import com.maum.backend.exception.NotFoundException
import com.maum.backend.exception.SelfFollowException
import com.maum.backend.repository.follow.FollowRepository
import com.maum.backend.repository.user.UserRepository
import org.assertj.core.api.Assertions.assertThat
import org.junit.jupiter.api.DisplayName
import org.junit.jupiter.api.Nested
import org.junit.jupiter.api.Test
import org.junit.jupiter.api.assertThrows
import org.junit.jupiter.api.extension.ExtendWith
import org.mockito.InjectMocks
import org.mockito.Mock
import org.mockito.Mockito.never
import org.mockito.Mockito.verify
import org.mockito.junit.jupiter.MockitoExtension
import org.mockito.kotlin.any
import org.mockito.kotlin.argumentCaptor
import org.mockito.kotlin.whenever
import java.time.LocalDateTime

@ExtendWith(MockitoExtension::class)
@DisplayName("UserService 팔로우 기능 단위 테스트")
class UserServiceTest {

    @Mock
    private lateinit var userRepository: UserRepository

    @Mock
    private lateinit var followRepository: FollowRepository

    @InjectMocks
    private lateinit var userService: UserService

    // ─── 테스트 픽스처 ────────────────────────────────────────────────────────

    private val followerId = "user-follower-001"
    private val followingId = "user-following-002"

    private fun makeUser(id: String) = UserEntity(id = id, nickname = "user_$id")

    private fun makeFollow(
        followerId: String = this.followerId,
        followingId: String = this.followingId,
    ) = FollowEntity(
        id = "follow-id-001",
        followerId = followerId,
        followingId = followingId,
        createdAt = LocalDateTime.now(),
    )

    // ─── follow() ─────────────────────────────────────────────────────────────

    @Nested
    @DisplayName("follow() - 팔로우 실행")
    inner class Follow {

        @Test
        fun `should 팔로우 성공 시 FollowEntity를 저장하고 반환한다`() {
            // given
            val savedFollow = makeFollow()
            whenever(userRepository.existsById(followerId)).thenReturn(true)
            whenever(userRepository.existsById(followingId)).thenReturn(true)
            whenever(followRepository.existsByFollowerIdAndFollowingId(followerId, followingId))
                .thenReturn(false)
            whenever(followRepository.save(any<FollowEntity>())).thenReturn(savedFollow)

            // when
            val result = userService.follow(followerId, followingId)

            // then
            assertThat(result.followerId).isEqualTo(followerId)
            assertThat(result.followingId).isEqualTo(followingId)

            val captor = argumentCaptor<FollowEntity>()
            verify(followRepository).save(captor.capture())
            assertThat(captor.firstValue.followerId).isEqualTo(followerId)
            assertThat(captor.firstValue.followingId).isEqualTo(followingId)
        }

        @Test
        fun `should throw SelfFollowException 자기 자신을 팔로우하면 예외를 던진다`() {
            // given
            val sameUserId = "user-001"

            // when & then
            assertThrows<SelfFollowException> {
                userService.follow(sameUserId, sameUserId)
            }

            // 자기 자신 팔로우 시 Repository 호출 없어야 함
            verify(userRepository, never()).existsById(any())
            verify(followRepository, never()).save(any())
        }

        @Test
        fun `should throw NotFoundException 팔로워 사용자가 존재하지 않으면 예외를 던진다`() {
            // given
            whenever(userRepository.existsById(followerId)).thenReturn(false)

            // when & then
            val exception = assertThrows<NotFoundException> {
                userService.follow(followerId, followingId)
            }
            assertThat(exception.message).contains(followerId)

            verify(followRepository, never()).save(any())
        }

        @Test
        fun `should throw NotFoundException 팔로우 대상 사용자가 존재하지 않으면 예외를 던진다`() {
            // given
            whenever(userRepository.existsById(followerId)).thenReturn(true)
            whenever(userRepository.existsById(followingId)).thenReturn(false)

            // when & then
            val exception = assertThrows<NotFoundException> {
                userService.follow(followerId, followingId)
            }
            assertThat(exception.message).contains(followingId)

            verify(followRepository, never()).save(any())
        }

        @Test
        fun `should throw AlreadyFollowingException 이미 팔로우 중이면 예외를 던진다`() {
            // given
            whenever(userRepository.existsById(followerId)).thenReturn(true)
            whenever(userRepository.existsById(followingId)).thenReturn(true)
            whenever(followRepository.existsByFollowerIdAndFollowingId(followerId, followingId))
                .thenReturn(true)

            // when & then
            val exception = assertThrows<AlreadyFollowingException> {
                userService.follow(followerId, followingId)
            }
            assertThat(exception.message).contains(followerId).contains(followingId)

            verify(followRepository, never()).save(any())
        }
    }

    // ─── unfollow() ───────────────────────────────────────────────────────────

    @Nested
    @DisplayName("unfollow() - 언팔로우 실행")
    inner class Unfollow {

        @Test
        fun `should 언팔로우 성공 시 FollowEntity를 삭제한다`() {
            // given
            val follow = makeFollow()
            whenever(followRepository.findByFollowerIdAndFollowingId(followerId, followingId))
                .thenReturn(follow)

            // when
            userService.unfollow(followerId, followingId)

            // then
            verify(followRepository).delete(follow)
        }

        @Test
        fun `should throw NotFoundException 팔로우 관계가 없으면 예외를 던진다`() {
            // given
            whenever(followRepository.findByFollowerIdAndFollowingId(followerId, followingId))
                .thenReturn(null)

            // when & then
            val exception = assertThrows<NotFoundException> {
                userService.unfollow(followerId, followingId)
            }
            assertThat(exception.message).contains(followerId).contains(followingId)

            verify(followRepository, never()).delete(any<FollowEntity>())
        }
    }

    // ─── getFollowings() ──────────────────────────────────────────────────────

    @Nested
    @DisplayName("getFollowings() - 팔로잉 목록 조회")
    inner class GetFollowings {

        @Test
        fun `should 팔로잉 목록을 반환한다`() {
            // given
            val userId = "user-001"
            val followings = listOf(
                makeFollow(followerId = userId, followingId = "target-001"),
                makeFollow(followerId = userId, followingId = "target-002"),
            )
            whenever(userRepository.existsById(userId)).thenReturn(true)
            whenever(followRepository.findAllByFollowerId(userId)).thenReturn(followings)

            // when
            val result = userService.getFollowings(userId)

            // then
            assertThat(result).hasSize(2)
            assertThat(result.map { it.followingId })
                .containsExactlyInAnyOrder("target-001", "target-002")
            verify(followRepository).findAllByFollowerId(userId)
        }

        @Test
        fun `should 팔로잉이 없으면 빈 목록을 반환한다`() {
            // given
            val userId = "user-no-following"
            whenever(userRepository.existsById(userId)).thenReturn(true)
            whenever(followRepository.findAllByFollowerId(userId)).thenReturn(emptyList())

            // when
            val result = userService.getFollowings(userId)

            // then
            assertThat(result).isEmpty()
        }

        @Test
        fun `should throw NotFoundException 존재하지 않는 사용자의 팔로잉 조회 시 예외를 던진다`() {
            // given
            val nonExistentUserId = "ghost-user"
            whenever(userRepository.existsById(nonExistentUserId)).thenReturn(false)

            // when & then
            assertThrows<NotFoundException> {
                userService.getFollowings(nonExistentUserId)
            }

            verify(followRepository, never()).findAllByFollowerId(any())
        }
    }

    // ─── getFollowers() ───────────────────────────────────────────────────────

    @Nested
    @DisplayName("getFollowers() - 팔로워 목록 조회")
    inner class GetFollowers {

        @Test
        fun `should 팔로워 목록을 반환한다`() {
            // given
            val userId = "user-001"
            val followers = listOf(
                makeFollow(followerId = "fan-001", followingId = userId),
                makeFollow(followerId = "fan-002", followingId = userId),
                makeFollow(followerId = "fan-003", followingId = userId),
            )
            whenever(userRepository.existsById(userId)).thenReturn(true)
            whenever(followRepository.findAllByFollowingId(userId)).thenReturn(followers)

            // when
            val result = userService.getFollowers(userId)

            // then
            assertThat(result).hasSize(3)
            assertThat(result.map { it.followerId })
                .containsExactlyInAnyOrder("fan-001", "fan-002", "fan-003")
        }

        @Test
        fun `should 팔로워가 없으면 빈 목록을 반환한다`() {
            // given
            val userId = "lonely-user"
            whenever(userRepository.existsById(userId)).thenReturn(true)
            whenever(followRepository.findAllByFollowingId(userId)).thenReturn(emptyList())

            // when
            val result = userService.getFollowers(userId)

            // then
            assertThat(result).isEmpty()
        }

        @Test
        fun `should throw NotFoundException 존재하지 않는 사용자의 팔로워 조회 시 예외를 던진다`() {
            // given
            val nonExistentUserId = "ghost-user"
            whenever(userRepository.existsById(nonExistentUserId)).thenReturn(false)

            // when & then
            assertThrows<NotFoundException> {
                userService.getFollowers(nonExistentUserId)
            }

            verify(followRepository, never()).findAllByFollowingId(any())
        }
    }

    // ─── isFollowing() ────────────────────────────────────────────────────────

    @Nested
    @DisplayName("isFollowing() - 팔로우 여부 확인")
    inner class IsFollowing {

        @Test
        fun `should 팔로우 중이면 true를 반환한다`() {
            // given
            whenever(followRepository.existsByFollowerIdAndFollowingId(followerId, followingId))
                .thenReturn(true)

            // when
            val result = userService.isFollowing(followerId, followingId)

            // then
            assertThat(result).isTrue()
        }

        @Test
        fun `should 팔로우 중이지 않으면 false를 반환한다`() {
            // given
            whenever(followRepository.existsByFollowerIdAndFollowingId(followerId, followingId))
                .thenReturn(false)

            // when
            val result = userService.isFollowing(followerId, followingId)

            // then
            assertThat(result).isFalse()
        }

        @Test
        fun `should 자기 자신에 대한 팔로우 여부도 Repository에 위임한다`() {
            // given
            val userId = "self-user"
            whenever(followRepository.existsByFollowerIdAndFollowingId(userId, userId))
                .thenReturn(false)

            // when
            val result = userService.isFollowing(userId, userId)

            // then
            assertThat(result).isFalse()
            verify(followRepository).existsByFollowerIdAndFollowingId(userId, userId)
        }
    }
}
